pub fn binding(id: ImportId) -> &'static AbiBinding {
    &ABI_BINDINGS[id as usize]
}

pub fn core_signature(id: CoreSignatureId) -> &'static CoreSignature {
    &CORE_SIGNATURES[id as usize]
}

pub fn find_binding(module: &str, name: &str) -> Option<&'static AbiBinding> {
    if let Some(binding) = ABI_BINDINGS
        .iter()
        .find(|binding| binding.module == module && binding.name == name)
    {
        return Some(binding);
    }
    let alias = ALIAS_BINDINGS
        .iter()
        .find(|alias| alias.alias_module == module && binding(alias.import).name == name)?;
    Some(binding(alias.import))
}
